function DressConfig.loadStoreTable()
    local items = FileUtil.getConfigFromCsv("setting/StoreTabSetting.csv", 3)
    for _, item in pairs(items) do
        table.insert(storeTable, {
            Id = tonumber(item.Id),
            Name = tostring(item.Name),
            Icon = tostring(item.Icon),
            Type = tonumber(item.Type)
        })
    end
    table.sort(storeTable, function(a, b)
        if a.Id < b.Id then
            return true
        else
            return false
        end
    end)
end

function DressConfig.loadDress()
    local items = FileUtil.getConfigFromCsv("setting/DressSetting.csv", 3)
    for _, item in pairs(items) do
        local temp
        if item.HasGet == 1 then
            temp = "DRESS_STATUS_HAS_GET"
        else
            temp = "DRESS_STATUS_LOCK"
        end
        dressConfig[item.Id] = {
            Id = tonumber(item.Id),
            ItemId = tonumber(item.ItemId),
            TabType = tonumber(item.TabType),
            Name = tostring(item.Name),
            Image = tostring(item.Image),
            LockImage = tostring(item.LockImage),
            Actor = tostring(item.Actor),
            BodyId = tostring(item.BodyId),
            ModelActorBody = tostring(item.ModelActorBody),
            ModelActorBodyId = tostring(item.ModelActorBodyId),
            Icon = tostring(item.Icon),
            PriceType = tonumber(item.PriceType),
            Price = tonumber(item.Price),
            UnlockLevel = tonumber(item.UnlockLevel),
            LockTip = tostring(item.LockTip),
            SortWeight = tonumber(item.SortWeight),
            HasGet = tonumber(item.HasGet),
            Describe = tostring(item.Describe),
            ChipImg = tostring(item.ChipImg),
            Status = temp
        }
    end
end

function DressConfig:getDressTables()
