function DressConfig:getDressConfigByType(type)
    if dressConfig == nil then
        return false
    end
    local result = {}
    for _, item in pairs(dressConfig) do
        if item.TabType == type then
            table.insert(result, item)
        end
    end
    local statue = {}
    for _, dress in pairs(result) do
        statue[dress.Id] = UIDressStore:getStatuesById(dress.Id)
    end
    table.sort(result, function(a, b)
        if statue[a.Id] ~= statue[b.Id] then
            if statue[a.Id] == 2 and statue[b.Id] == 1 then
                return a.SortWeight > b.SortWeight
            end
            if statue[a.Id] == 1 and statue[b.Id] == 2 then
                return a.SortWeight > b.SortWeight
            end
            return statue[a.Id] > statue[b.Id]
        end
        return a.SortWeight > b.SortWeight
    end)
    return result
end

